import redis
import json

r = redis.Redis(host='localhost', port=6379, db=0)

class ConversationState:
    def __init__(self, session_id: str):
        self.session_id = f'voice:{session_id}'

    def append(self, transcript: str, response: str, intent: str):
        state = {
            'turns': r.lrange(self.session_id, 0, 99),
            'latest_intent': intent,
            'timestamp': time.time()
        }
        r.lpush(self.session_id, json.dumps({
            'transcript': transcript,
            'response': response,
            'intent': intent
        }))
        r.ltrim(self.session_id, 0, 99)  # Keep last 100 turns

    def get_context(self) -> str:
        turns = r.lrange(self.session_id, 0, 9)
        return ' | '.join([json.loads(t)['transcript'] for t in turns])

# Usage in task
state = ConversationState('user_123')
context = state.get_context()
listener_task.description += f' | Context: {context}'

import re

HAZARDOUS_PATTERNS = [
    r'\b(kill|die|suicide)\b',
    r'\b(hate|racist|terror)\w*\b',
    r'http\S+\.(exe|bat|sh|py)\b'
]

class SafetyFilter:
    @staticmethod
    def check(response: str, intent: str) -> bool:
        # Content safety
        for pattern in HAZARDOUS_PATTERNS:
            if re.search(pattern, response, re.IGNORECASE):
                return False

        # Intent drift check
        safe_intents = ['greeting', 'question', 'request', 'confirmation']
        if intent not in safe_intents:
            return False

        # Length limits for voice
        return len(response) < 200

# Wrap crew output
if SafetyFilter.check(result.response, result.intent):
    tts_audio = elevenlabs.generate(result.response)
else:
    tts_audio = elevenlabs.generate('I can\'t help with that request.')

