from vex import Vex, Guardrail

vex = Vex(api_key='your-vex-key')

def vex_task_callback(task, output, **context):
    # Track delegation depth
    delegation_depth = context.get('delegation_depth', 0)

    guardrail = Guardrail(
        name='no_loops',
        spec={
            'max_delegations': 3,
            'latency_budget_ms': 300,
            'output': output.model_dump()
        }
    )

    result = vex.verify(guardrail)
    if not result.pass:
        raise Exception(f'Guardrail failed: {result.reason}')

    return {
        'output': output,
        'delegation_depth': delegation_depth + 1,
        'verified': True
    }

# Attach to CrewAI task
listener_task.callback = vex_task_callback

def coherence_guardrail(task_output, history: str):
    import time

    start_time = time.time()

    guardrail = Guardrail(
        name='voice_coherence',
        spec={
            'metrics': {
                'latency_ms': (time.time() - start_time) * 1000,
                'max_latency': 800
            },
            'semantic_similarity': {
                'reference': history[-200:],
                'candidate': task_output.response,
                'min_score': 0.7
            },
            'appropriateness': {
                'categories': ['safe', 'on_topic'],
                'min_score': 0.9
            }
        }
    )

    return vex.verify(guardrail)

# Pipeline integration
